#!run
import {dir} from "@acepad/here";
const h=dir(import.meta.url);
export async function main(p5="test.p5.js"){
  p5=this.resolve(p5);
  const w=await this.webpage(
  h.rel("html/index.html"));
  const i=(w.element.querySelector("iframe"));
  while(!i.contentWindow.boot)await this.sleep(0.1)
  i.contentWindow.boot(p5.path());
}